sql:
SELECT title
FROM questions
WHERE view_count = (SELECT MAX(view_count) FROM questions);

SELECT title, score, AVG(score) OVER () AS avg_question_score
FROM questions
WHERE view_count >= 100;

SELECT question_id, score
FROM questions
WHERE view_count > (
    SELECT AVG(view_count) 
    FROM questions
) AND score > (
    SELECT AVG(score) 
    FROM questions
);

external_knowledge:
- 'Planted seeds in the garden of knowledge' refers to posting questions;
- 'Seen by at least 100 curious minds' refers to questions with a view count of at least 100;
- 'Blossoms above the average beauty of all answers' refers to answers with a score greater than the average score of all answers.

sql:
SELECT SUM(view_count) AS total_views
FROM questions
WHERE (LENGTH(viewed_by) - LENGTH(replace(viewed_by, ',', '')) + 1) > 100;

external_knowledge:
- "seeds" refer to questions;
- "flowers" refer to answers;
- "gardeners" refer to users;
- "most prolific" means the users with the highest number of posts.

- "Gardeners" refer to users on a content platform;
- "Plots" represent the questions, answers, and comments posted by users;
- "Flourished to at least 100 views" means the total views from questions, answers, and edited comments are 100 or more;
- "Influential gardeners" are ranked by the total views on their contributions.

sql:
SELECT SUM(view_count) AS total_views
FROM questions q
WHERE (
    SELECT COUNT(DISTINCT user_id)
    FROM (
        SELECT CAST(SUBSTR(t.value, 2, LENGTH(t.value) - 2) AS INTEGER) AS user_id
        FROM questions q2, json_each('[' || REPLACE(q.viewed_by, ' ', '') || ']') t
        WHERE q.question_id = q2.question_id
    ) t2
) > 100;

SELECT COUNT(DISTINCT q.question_id) AS total_questions_by_answer_users
FROM questions q
WHERE q.user_id IN (
  SELECT DISTINCT a.user_id
  FROM answers a
);

